#[extendr]
#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
pub struct LlmUsage {
    /// The LLM model identifier (e.g. "openai/gpt-4o", "anthropic/claude-sonnet-4-20250514").
    pub model: String,
    /// The pipeline stage that triggered this LLM call
    /// (e.g. "vlm_ocr", "structured_extraction", "embeddings").
    pub source: String,
    /// Number of input/prompt tokens consumed.
    pub input_tokens: Option<f64>,
    /// Number of output/completion tokens generated.
    pub output_tokens: Option<f64>,
    /// Total tokens (input + output).
    pub total_tokens: Option<f64>,
    /// Estimated cost in USD based on the provider's published pricing.
    pub estimated_cost: Option<f64>,
    /// Why the model stopped generating (e.g. "stop", "length", "content_filter").
    pub finish_reason: Option<String>,
}

#[extendr]
impl LlmUsage {}

#[extendr]
pub fn new_llmusage(
    model: Option<String>,
    source: Option<String>,
    input_tokens: Option<f64>,
    output_tokens: Option<f64>,
    total_tokens: Option<f64>,
    estimated_cost: Option<f64>,
    finish_reason: Option<String>,
) -> LlmUsage {
    let mut __out = <LlmUsage>::default();
    if let Some(v) = model {
        __out.model = v;
    }
    if let Some(v) = source {
        __out.source = v;
    }
    if let Some(v) = input_tokens {
        __out.input_tokens = Some(v);
    }
    if let Some(v) = output_tokens {
        __out.output_tokens = Some(v);
    }
    if let Some(v) = total_tokens {
        __out.total_tokens = Some(v);
    }
    if let Some(v) = estimated_cost {
        __out.estimated_cost = Some(v);
    }
    if let Some(v) = finish_reason {
        __out.finish_reason = Some(v);
    }
    __out
}

