#[extendr]
pub fn new_boundingbox(x0: Option<f64>, y0: Option<f64>, x1: Option<f64>, y1: Option<f64>) -> BoundingBox {
    let mut __out = <BoundingBox>::default();
    if let Some(v) = x0 {
        __out.x0 = v;
    }
    if let Some(v) = y0 {
        __out.y0 = v;
    }
    if let Some(v) = x1 {
        __out.x1 = v;
    }
    if let Some(v) = y1 {
        __out.y1 = v;
    }
    __out
}

