#[extendr]
pub fn new_paddleocrconfig(
    language: Option<String>,
    cache_dir: Option<String>,
    use_angle_cls: Option<bool>,
    enable_table_detection: Option<bool>,
    det_db_thresh: Option<f64>,
    det_db_box_thresh: Option<f64>,
    det_db_unclip_ratio: Option<f64>,
    det_limit_side_len: Option<i32>,
    rec_batch_num: Option<i32>,
    padding: Option<i32>,
    drop_score: Option<f64>,
    model_tier: Option<String>,
) -> PaddleOcrConfig {
    let mut __out = <PaddleOcrConfig>::default();
    if let Some(v) = language {
        __out.language = v;
    }
    if let Some(v) = cache_dir {
        __out.cache_dir = Some(v);
    }
    if let Some(v) = use_angle_cls {
        __out.use_angle_cls = v;
    }
    if let Some(v) = enable_table_detection {
        __out.enable_table_detection = v;
    }
    if let Some(v) = det_db_thresh {
        __out.det_db_thresh = v;
    }
    if let Some(v) = det_db_box_thresh {
        __out.det_db_box_thresh = v;
    }
    if let Some(v) = det_db_unclip_ratio {
        __out.det_db_unclip_ratio = v;
    }
    if let Some(v) = det_limit_side_len {
        __out.det_limit_side_len = v;
    }
    if let Some(v) = rec_batch_num {
        __out.rec_batch_num = v;
    }
    if let Some(v) = padding {
        __out.padding = v;
    }
    if let Some(v) = drop_score {
        __out.drop_score = v;
    }
    if let Some(v) = model_tier {
        __out.model_tier = v;
    }
    __out
}

