pub fn resolve(
    preset: &Preset,
    custom_schema: Option<String>,
    context: Option<HashMap<String, String>>,
) -> Result<ResolvedPreset> {
    let preset_core: xberg::Preset = preset.clone().into();

    xberg::resolve(
        &preset_core,
        custom_schema.as_ref().and_then(|s| serde_json::from_str(s).ok()),
        &context
            .unwrap_or_default()
            .into_iter()
            .collect::<std::collections::BTreeMap<_, _>>(),
    )
    .map(Into::into)
    .map_err(|e| {
        extendr_api::Error::Other(
            e.to_string()
                .replace(":", "_")
                .replace("/", "_")
                .replace("-", "_")
                .chars()
                .take(255)
                .collect::<String>(),
        )
    })
}

