#[allow(clippy::missing_errors_doc)]
#[extendr]
pub fn embed_texts_async(_texts: Vec<String>, _config: &EmbeddingConfig) -> String {
    match (|| -> Result<String> {
        let _config_core: xberg::EmbeddingConfig = (*_config).clone().into();
        let rt = tokio::runtime::Runtime::new().map_err(|e| {
            extendr_api::Error::Other(
                e.to_string()
                    .replace(":", "_")
                    .replace("/", "_")
                    .replace("-", "_")
                    .chars()
                    .take(255)
                    .collect::<String>(),
            )
        })?;
        let result = rt.block_on(async {
            xberg::embed_texts_async(_texts, &_config_core).await.map_err(|e| {
                extendr_api::Error::Other(
                    e.to_string()
                        .replace(":", "_")
                        .replace("/", "_")
                        .replace("-", "_")
                        .chars()
                        .take(255)
                        .collect::<String>(),
                )
            })
        })?;

        serde_json::to_string(&result).map_err(|e| {
            extendr_api::Error::Other(
                e.to_string()
                    .replace(":", "_")
                    .replace("/", "_")
                    .replace("-", "_")
                    .chars()
                    .take(255)
                    .collect::<String>(),
            )
        })
    })() {
        Ok(v) => v,
        Err(e) => extendr_api::throw_r_error(&format!("{:?}", e)),
    }
}

