impl ROcrBackendBridge {
    /// Create a new bridge wrapping an R object (named list of functions).
    ///
    /// Validates that the R object provides all required methods.
    pub fn new(r_obj: extendr_api::Robj) -> std::result::Result<Self, String> {
        match r_obj.dollar("process_image") {
            Ok(v) if !v.is_null() && !v.is_na() => {}
            _ => return Err("R object missing required method: process_image".to_string()),
        }
        match r_obj.dollar("supports_language") {
            Ok(v) if !v.is_null() && !v.is_na() => {}
            _ => return Err("R object missing required method: supports_language".to_string()),
        }
        match r_obj.dollar("backend_type") {
            Ok(v) if !v.is_null() && !v.is_na() => {}
            _ => return Err("R object missing required method: backend_type".to_string()),
        }

        let cached_name: String = match r_obj.dollar("name") {
            Ok(v) if !v.is_null() && !v.is_na() => {
                if let Some(s) = v.as_str() {
                    s.to_string()
                } else {
                    "unknown".to_string()
                }
            }
            _ => "unknown".to_string(),
        };

        Ok(Self {
            inner: r_obj,
            cached_name,
        })
    }
}

