#[async_trait::async_trait]
impl xberg::OcrBackend for ROcrBackendBridge {
    async fn process_image(
        &self,
        image_bytes: &[u8],
        config: &xberg::OcrConfig,
    ) -> std::result::Result<xberg::ExtractionResult, xberg::XbergError> {
        let cached_name = self.cached_name.clone();
        let cached_name_inner = cached_name.clone();
        let send_r_obj = SendRobj(self.inner.clone());

        let image_bytes = image_bytes.to_vec();

        let config_owned = (*config).clone();

        tokio::task::spawn_blocking(move || {
            // Call `into_inner()` on the whole `SendRobj` value so the closure captures the whole
            // `SendRobj` (which is `Send`) rather than just the inner `Robj` field (which is `!Send`)
            // under 2021+ disjoint-capture rules. The method takes `self` by value, forcing the
            // closure to move the whole wrapper.
            let r_obj = send_r_obj.into_inner();
            let maybe_fn = r_obj.dollar("process_image");
            let fn_robj = match maybe_fn {
                Ok(v) if !v.is_null() && !v.is_na() => v,
                _ => {
                    return Err(xberg::XbergError::Other(format!(
                        "Plugin '{}' missing method 'process_image'",
                        cached_name_inner
                    )));
                }
            };

            let args = extendr_api::Pairlist::from_pairs(&[
                ("image_bytes", extendr_api::Robj::from(&image_bytes[..])),
                ("config", extendr_api::Robj::from(OcrConfig::from(config_owned.clone()))),
            ]);
            let result = fn_robj.call(args);

            // R callbacks return JSON-encoded strings (e.g. via `jsonlite::toJSON`). Parse the string
            // payload back into the trait return type. Note: `extendr_api::Robj` does not implement
            // `serde::Serialize`, so we cannot serialize it directly — the caller must serialize on
            // the R side.
            match result {
                Err(_) => Err(xberg::XbergError::Other(format!(
                    "Plugin '{}' method 'process_image' failed",
                    cached_name_inner
                ))),
                Ok(val) => {
                    let payload = val.as_str().unwrap_or("");
                    serde_json::from_str::<xberg::ExtractionResult>(payload).map_err(|_| {
                        xberg::XbergError::Other(format!(
                            "Plugin '{}' method 'process_image' deserialization failed",
                            cached_name_inner
                        ))
                    })
                }
            }
        })
        .await
        .map_err(|e| xberg::XbergError::Other(format!("spawn_blocking failed: {}", e)))?
    }

    fn supports_language(&self, lang: &str) -> bool {
        let maybe_fn = self.inner.dollar("supports_language");
        let fn_robj = match maybe_fn {
            Ok(v) if !v.is_null() && !v.is_na() => v,
            _ => return Default::default(),
        };

        let args = extendr_api::Pairlist::from_pairs(&[("lang", extendr_api::Robj::from(lang))]);
        let result = fn_robj.call(args);

        // Primitive return: extract directly from Robj without JSON deserialization
        match result {
            Err(_) => Default::default(),
            Ok(val) => {
                let int_val = val
                    .as_integer()
                    .map(|i| i != 0)
                    .or_else(|| val.as_real().map(|r| r != 0.0))
                    .unwrap_or(false);
                int_val
            }
        }
    }

    fn backend_type(&self) -> xberg::OcrBackendType {
        let maybe_fn = self.inner.dollar("backend_type");
        let fn_robj = match maybe_fn {
            Ok(v) if !v.is_null() && !v.is_na() => v,
            _ => return Default::default(),
        };

        let result = fn_robj.call(extendr_api::Pairlist::new());

        // R callbacks return JSON-encoded strings (e.g. via `jsonlite::toJSON`). Parse the string
        // payload back into the trait return type. Note: `extendr_api::Robj` does not implement
        // `serde::Serialize`, so we cannot serialize it directly — the caller must serialize on
        // the R side.
        match result {
            Err(_) => Default::default(),
            Ok(val) => {
                let payload = val.as_str().unwrap_or("");
                match serde_json::from_str::<xberg::OcrBackendType>(payload) {
                    Ok(parsed) => parsed,
                    Err(_) => Default::default(),
                }
            }
        }
    }
}

#[extendr]
pub fn register_ocr_backend(r_backend: extendr_api::Robj) -> extendr_api::Result<()> {
    let required_methods = ["process_image", "supports_language", "backend_type"];
    for method in &required_methods {
        match r_backend.dollar(method) {
            Ok(v) if !v.is_null() && !v.is_na() => {}
            _ => {
                return Err(extendr_api::Error::Other(format!(
                    "Backend missing required method: {}",
                    method
                )));
            }
        }
    }

    let wrapper = ROcrBackendBridge::new(r_backend).map_err(|e| extendr_api::Error::Other(e))?;
    let arc: Arc<dyn xberg::OcrBackend> = Arc::new(wrapper);

    let registry = xberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();
    registry
        .register(arc)
        .map_err(|e| extendr_api::Error::Other(format!("Failed to register backend: {}", e)))
}

#[extendr]
pub fn unregister_ocr_backend(name: String) -> extendr_api::Result<()> {
    xberg::plugins::ocr_backend::unregister_ocr_backend(&name).map_err(|e| extendr_api::Error::Other(format!("{}", e)))
}

